   332|
   333|function encryptField(plaintext: string): string {
   334|  if (!plaintext) return '';
   335|  const key = encryptionKey();
   336|  const iv = randomBytes(12);
   337|  const cipher = createCipheriv('aes-256-gcm', key, iv);
   338|  const ct = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
   339|  const tag = cipher.getAuthTag();
   340|  const payload: EncryptedPayload = {
   341|    iv: iv.toString('base64'),
   342|    ct: ct.toString('base64'),
   343|    tag: tag.toString('base64'),
   344|  };
   345|  return JSON.stringify(payload);
   346|}
   347|
   348|function decryptField(encoded: string): string {
   349|  if (!encoded) return '';
   350|  try {
   351|    const payload = JSON.parse(encoded) as EncryptedPayload;
   352|    const key = encryptionKey();
   353|    const iv = Buffer.from(payload.iv, 'base64');
   354|    const ct = Buffer.from(payload.ct, 'base64');
   355|    const tag = Buffer.from(payload.tag, 'base64');
   356|    const decipher = createDecipheriv('aes-256-gcm', key, iv);
   357|    decipher.setAuthTag(tag);
   358|    const pt = Buffer.concat([decipher.update(ct), decipher.final()]);
   359|    return pt.toString('utf8');
   360|  } catch {
   361|    return '';
   362|  }
