   550|export interface TransitionStateInput {
   551|  userId: string;
   552|  newState: AccountState;
   553|  reason: string;
   554|  operatorId: string;
   555|  operatorEmail: string;
   556|  hasFunds?: boolean;
   557|  ip?: string;
   558|  device?: string;
   559|}
   560|
   561|/**
   562| * Transition an account's state. Enforces:
   563| *   - cannot move to 'closed'/'archived' if account has funds (must be 'rejected' or 'locked' first)
   564| *   - never permanently locks a verified investor out: 'locked' can always be reversed to 'active'
   565| *   - financial history is always immutable
   566| */
   567|export async function transitionAccountState(input: TransitionStateInput): Promise<AccountStateRecord> {
   568|  if (!VALID_ACCOUNT_STATES.has(input.newState)) {
   569|    throw new Error(`Invalid account state: ${input.newState}`);
   570|  }
   571|  const states = await readStore<AccountStateRecord[]>(ACCOUNT_STATES_FILE(), []);
   572|  const idx = states.findIndex((s) => s.userId === input.userId);
   573|  const current: AccountStateRecord = idx >= 0
   574|    ? states[idx]
   575|    : await getAccountStateRecord(input.userId);
   576|  const previousState = current.accountState;
   577|  const hasFunds = input.hasFunds ?? current.hasFunds;
   578|
   579|  // Deletion-protection guard: never archive/close an account that still holds funds.
   580|  if ((input.newState === 'archived' || input.newState === 'closed') && hasFunds) {
   581|    await recordProtectionAudit({
   582|      actorAdminId: input.operatorId,
   583|      actorEmail: input.operatorEmail,
   584|      action: 'state_transition_blocked_has_funds',
   585|      targetUserId: input.userId,
   586|      targetEntity: 'account_state',
   587|      targetId: current.id,
   588|      ip: input.ip,
   589|      device: input.device,
   590|      oldValue: previousState,
   591|      newValue: input.newState,
   592|      reason: input.reason,
   593|    });
   594|    throw new Error('BLOCKED_HAS_FUNDS: account with financial records cannot be archived or closed. Move funds first.');
   595|  }
   596|
   597|  const updated: AccountStateRecord = {
   598|    ...current,
   599|    accountState: input.newState,
   600|    reason: input.reason,
   601|    operatorId: input.operatorId,
   602|    operatorEmail: input.operatorEmail,
   603|    previousState,
   604|    hasFunds,
   605|    immutableFinancialHistory: true,
   606|    updatedAt: nowIso(),
   607|  };
   608|
   609|  if (idx >= 0) {
   610|    states[idx] = updated;
   611|  } else {
   612|    states.push(updated);
   613|  }
   614|  await writeStore(ACCOUNT_STATES_FILE(), states);
   615|  await recordProtectionAudit({
   616|    actorAdminId: input.operatorId,
   617|    actorEmail: input.operatorEmail,
   618|    action: 'account_state_transition',
   619|    targetUserId: input.userId,
   620|    targetEntity: 'account_state',
   621|    targetId: updated.id,
   622|    ip: input.ip,
   623|    device: input.device,
   624|    oldValue: previousState,
   625|    newValue: input.newState,
   626|    reason: input.reason,
   627|  });
   628|  return updated;
   629|}
