   895|  if (idx < 0) throw new Error('Recovery request not found.');
   896|  const req = requests[idx];
   897|  if (req.status === 'expired' || req.status === 'completed') {
   898|    throw new Error(`Recovery request already ${req.status}.`);
   899|  }
   900|  req.attempts += 1;
   901|  if (hashValue(input.code) !== req.verificationCodeHash) {
   902|    if (req.attempts >= 5) {
   903|      req.status = 'expired';
   904|    }
   905|    req.updatedAt = nowIso();
   906|    requests[idx] = req;
   907|    await writeStore(RECOVERY_REQUESTS_FILE(), requests);
   908|    await recordProtectionAudit({
   909|      action: 'recovery_verify_failed',
   910|      targetEntity: 'recovery_request',
   911|      targetId: req.id,
   912|      targetUserId: req.userId,
   913|      ip: input.ip,
   914|      device: input.device,
   915|      newValue: { attempts: req.attempts },
   916|      reason: 'Incorrect verification code.',
   917|    });
   918|    throw new Error('Invalid verification code.');
   919|  }
   920|  req.verified = true;
   921|  req.status = 'verified';
   922|  req.auditTrail.push({ at: nowIso(), actor: 'system', action: 'recovery_verified', detail: 'code matched' });
   923|  req.updatedAt = nowIso();
   924|  requests[idx] = req;
   925|  await writeStore(RECOVERY_REQUESTS_FILE(), requests);
   926|  await recordProtectionAudit({
