   819|      }
   820|      console.log('[IVXOwnerRegistration] Owner profile retry upsert failed:', retry.error.message);
   821|      return false;
   822|    }
   823|    console.log('[IVXOwnerRegistration] Owner profile upsert failed:', message);
   824|    return false;
   825|  }
